//! Flash-resident static data tables: species, moves, type chart.
//!
//! Generated by `build.rs` from `data/gen1_*.json`. Total flash budget в‰€ 10 KB.

use crate::types::Type;

/// One species' base data. ~32 B packed.
#[derive(Clone, Copy, Debug)]
pub struct SpeciesEntry {
    pub id: &'static str,
    pub name: &'static str,
    pub primary_type: Type,
    pub secondary_type: Type, // Type::None for single-typed mons
    /// HP, Atk, Def, Spc, Speed. Gen 1 has no Sp.Atk/Sp.Def split вЂ” `spc` is "Special".
    pub base_stats: [u16; 5],
    pub catch_rate: u8,
    pub base_exp_yield: u16,
}

#[repr(u8)]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum MoveCategory {
    Physical = 0,
    Special,
    Status,
}

/// The dispatch tag for a move's on-hit behavior. Each variant is implemented
/// in the move executor (task #5 / #6). All Gen 1 moves map to exactly one.
#[repr(u8)]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum MoveEffectKind {
    /// Plain damage. No rider.
    Damage = 0,
    /// Damage + chance to inflict status. `param0`=status_id, `param1`=chance/256.
    DamageMaybeStatus,
    /// Damage + chance to flinch. `param0`=chance/256.
    DamageMaybeFlinch,
    /// Damage + chance to boost target stat. `param0`=stat_id, `param1`=delta_i8, `param2`=chance/256.
    DamageMaybeBoostTarget,
    /// Damage + chance to boost user stat.
    DamageMaybeBoostSelf,
    /// Stage change, self.    `param0`=stat_id, `param1`=delta_i8.
    BoostSelf,
    /// Stage change, target.  `param0`=stat_id, `param1`=delta_i8.
    BoostTarget,
    /// Always inflict status. `param0`=status_id.
    StatusOnly,
    /// Multi-hit (2вЂ“5 weighted: 3/8 for 2, 3/8 for 3, 1/8 for 4, 1/8 for 5).
    MultiHit2to5,
    /// Multi-hit fixed N.     `param0`=hits.
    MultiHitFixed,
    /// Drain HP (% of damage dealt heals user). `param0`=numerator, `param1`=denominator.
    DrainHp,
    /// Recoil 1/4 of damage dealt.
    Recoil1of4,
    /// 1 HP self-damage on miss (Hi Jump Kick / Jump Kick in Gen 1).
    CrashOnMiss,
    /// OHKO. Misses if user.speed < target.speed, else 30% accuracy.
    Ohko,
    /// Force the target to switch. Always fails in trainer battles in Gen 1.
    ForceSwitchTarget,
    /// Fixed damage = user's level.
    LevelDamage,
    /// Fixed damage of `param0`.
    FlatDamage,
    /// Psywave: random 1..=1.5*level.
    Psywave,
    /// Set target HP to 50% (Super Fang).
    HalfHp,
    /// Heal self by 50% max HP.
    HealHalf,
    /// Rest вЂ” sleep 2 turns, full heal.
    Rest,
    /// Two-turn move (charge then hit). `param0`=invulnerable_during_charge (0/1).
    TwoTurn,
    /// Bide вЂ” store damage 2вЂ“3 turns, return 2Г—.
    Bide,
    /// Hyper Beam (recharge unless KO).
    HyperBeam,
    /// Counter вЂ” mirror back 2Г— last Normal/Fighting damage.
    Counter,
    /// Mirror Move вЂ” copy opponent's last move.
    MirrorMove,
    /// Mimic вЂ” replace a slot with target's last move (PP=5).
    Mimic,
    /// Transform вЂ” copy species/stats/types/moves/stages from target.
    Transform,
    /// Substitute вЂ” 1/4 HP + 1 sub.
    Substitute,
    /// Disable вЂ” random target move, 1вЂ“8 turns.
    Disable,
    /// Wrap-like trap: 2вЂ“5 turns, target trapped, small damage per turn.
    Wrap,
    /// Leech Seed вЂ” drain 1/16 EOT.
    LeechSeed,
    /// Light Screen вЂ” Spc damage doublers for the user's team.
    LightScreen,
    /// Reflect вЂ” Phys damage doublers for the user's team.
    Reflect,
    /// Mist вЂ” immune to opponent stat reductions while active.
    Mist,
    /// Focus Energy вЂ” modifies crit rate (BUGGED: lowers in Gen 1).
    FocusEnergy,
    /// Conversion вЂ” copy target's type(s) onto user.
    Conversion,
    /// Haze вЂ” clear all stat stages on both sides.
    Haze,
    /// Metronome вЂ” choose a random move and execute it.
    Metronome,
    /// Pay Day вЂ” damage + narration only.
    PayDay,
    /// Self-Destruct / Explosion вЂ” halves target Def (Gen 1), KOs user.
    SelfDestruct,
    /// Splash and other status-no-ops.
    NoOp,
}

/// One move. ~24 B packed.
#[derive(Clone, Copy, Debug)]
pub struct MoveEntry {
    pub id: &'static str,
    pub name: &'static str,
    pub move_type: Type,
    pub category: MoveCategory,
    pub power: u8,        // 0 = no damage
    pub accuracy: u8,     // 0 = always hits (Swift)
    pub pp: u8,
    pub effect_kind: MoveEffectKind,
    pub effect_param0: u8,
    pub effect_param1: u8,
    /// Bit flags: 0x01 high-crit, 0x02 contact, 0x04 sound, 0x08 priority_plus1, 0x10 priority_minus1.
    pub flags: u8,
}

pub const FLAG_HIGH_CRIT: u8 = 0x01;
pub const FLAG_CONTACT:   u8 = 0x02;
pub const FLAG_SOUND:     u8 = 0x04;
pub const FLAG_PRIO_PLUS: u8 = 0x08;
pub const FLAG_PRIO_MINUS: u8 = 0x10;

/// Type-effectiveness multiplier Г—10: 0 = immune, 5 = ВЅ, 10 = 1Г—, 20 = 2Г—.
pub type TypeEffectiveness = u8;

// Generated `SPECIES`, `MOVES`, `TYPE_CHART`, plus lookup helpers.
include!(concat!(env!("OUT_DIR"), "/gen1_tables.rs"));

// в”Ђв”Ђ Lookups в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/// Find a species by lowercase ID string. O(log N).
pub fn species_by_id(id: &str) -> Option<&'static SpeciesEntry> {
    SPECIES.binary_search_by(|e| e.id.cmp(id)).ok().map(|i| &SPECIES[i])
}

/// Find a move by lowercase ID string. O(log N).
pub fn move_by_id(id: &str) -> Option<&'static MoveEntry> {
    MOVES.binary_search_by(|e| e.id.cmp(id)).ok().map(|i| &MOVES[i])
}

/// Type-effectiveness multiplier (Г—10). Use 1Г— for unknown.
pub fn type_effectiveness(attacker: Type, defender: Type) -> TypeEffectiveness {
    let a = attacker as usize;
    let d = defender as usize;
    if a < TYPE_COUNT && d < TYPE_COUNT {
        TYPE_CHART[a][d]
    } else {
        10
    }
}
